#include <iostream>
#include <iomanip>

class Calculator {
public:
    int add(int a, int b) {
        return a + b;
    }

    double add(double a, double b) {
        return a + b;
    }

    int add(int a, int b, int c) {
        return a + b + c;
    }
};

int main() {
    Calculator calc;
    std::cout << calc.add(5, 7) << std::endl;
    std::cout << std::fixed << std::setprecision(1) << calc.add(5.5, 7.2) << std::endl;
    std::cout << calc.add(1, 2, 3) << std::endl;
    return 0;
}
